document.addEventListener("DOMContentLoaded",()=>{const e=new IntersectionObserver(t=>{t.forEach(d=>{d.isIntersecting&&d.target.classList.add("in-view")})},{threshold:.1});document.querySelectorAll(".section-animate").forEach(t=>e.observe(t))});const o=document.getElementById("site-header"),s=document.getElementById("mobile-menu-btn"),n=document.getElementById("mobile-menu");window.addEventListener("scroll",()=>{window.scrollY>10?o?.classList.add("bg-background/80","backdrop-blur-md"):o?.classList.remove("bg-background/80","backdrop-blur-md")});s?.addEventListener("click",()=>{n?.classList.toggle("hidden")});n?.querySelectorAll("a").forEach(e=>{e.addEventListener("click",()=>{n.classList.add("hidden")})});
